parameters.jsonBody:
={{ JSON.stringify({
  "post_info": {
    "title": $json.caption || "My TikTok Video",
    "description": $json.caption || "",
    "privacy_level": "SELF_ONLY",
    "disable_duet": false,
    "disable_comment": false,
    "disable_stitch": false,
    "video_cover_timestamp_ms": 0
  },
  "source_info": {
    "source": "PULL_FROM_URL",
    "video_url": $json.video_url
  },
  "post_mode": "DIRECT_POST",
  "schedule_time": $json.schedule_epoch || Math.floor(Date.now() / 1000) + 86400
}) }}

={{ JSON.stringify({
  "snippet": {
    "title": ($json.yt_title || "My Short") + " #Shorts",
    "description": (Array.isArray($json.captions) ? $json.captions.join('\n') : ($json.caption || '')) + '\n\n' + ($json.hashtags || '#Shorts'),
    "tags": $json.tags || ["Roblox", "Shorts", "Gaming"],
    "categoryId": "20"
  },
  "status": {
    "privacyStatus": "private",
    "selfDeclaredMadeForKids": false,
    "publishAt": $json.schedule_iso || new Date(($json.schedule_epoch || Math.floor(Date.now() / 1000) + 86400) * 1000).toISOString(),
    "containsSyntheticMedia": true
  }
}) }}
